tool.command:
 
        obitaxonomy
        --no-progressbar
        #if str($options_obitaxo.mode_taxo) == "download_mode":
            --download-ncbi
        #else
            @TAXO_DIR@
            @RESTRICT_TO_TAXON@
            #if $options_obitaxo.taxid_part.dump
                --dump $options_obitaxo.taxid_part.dump
            #end if
            #if $options_obitaxo.taxid_part.parents
                --parents $options_obitaxo.taxid_part.parents
            #end if
            #if $options_obitaxo.taxid_part.sons
                --sons $options_obitaxo.taxid_part.sons
            #end if
            #if str($options_obitaxo.extract_taxo.extract_taxonomy) == 'extract_from_file':
                --extract-taxonomy '$options_obitaxo.extract_taxo.sequence_file'
                ${options_obitaxo.extract_taxo.with_leaves}
            #else
                #if $options_obitaxo.extract_taxo.name_query
                    '$options_obitaxo.extract_taxo.name_query'
                #end if
                ${options_obitaxo.extract_taxo.alternative_names}
                ${options_obitaxo.extract_taxo.fixed}
            #end if

            ${options_obitaxo.rank_list}

            #if str($options_obitaxo.output_conditional.output_format_obitaxo) == 'newick_output' :
                --newick-output
            #else
                ${options_obitaxo.output_conditional.with_path}
                ${options_obitaxo.output_conditional.with_query}
                ${options_obitaxo.output_conditional.without_parent}
                ${options_obitaxo.output_conditional.without_rank}
                ${options_obitaxo.output_conditional.without_scientific_name}
                @RANK@
            #end if

            ${options_obitaxo.without_root}
            ${options_obitaxo.update_taxid}
            ${options_obitaxo.fail_on_tax}
            > '$output'
        #end if
